variables_tf:
# =============================================================================
# Variables – OCI 3-Tier Web Application
# =============================================================================

# --- OCI Provider Authentication ---
variable "tenancy_ocid" {
  description = "OCID of the OCI tenancy."
  type        = string
}

variable "user_ocid" {
  description = "OCID of the OCI user used for provider authentication."
  type        = string
}

variable "fingerprint" {
  description = "Fingerprint of the API signing key used for provider authentication."
  type        = string
}

variable "private_key_path" {
  description = "Filesystem path to the OCI API private key PEM file."
  type        = string
  default     = "~/.oci/oci_api_key.pem"
}

variable "region" {
  description = "OCI region identifier (e.g., us-ashburn-1, eu-frankfurt-1)."
  type        = string
  default     = "us-ashburn-1"
}

variable "compartment_id" {
  description = "OCID of the compartment in which all resources will be created."
  type        = string
}

# --- Application Identity ---
variable "environment" {
  description = "Deployment environment name (e.g., production, staging). Maps CFN Parameter: Environment."
  type        = string
  default     = "production"
}

variable "project_name" {
  description = "Short project identifier used in resource display names and freeform tags."
  type        = string
  default     = "acme"
}

# --- Networking ---
# Set use_existing_vcn = true to mirror the CFN pattern where VpcId,
# PrivateSubnets, and PublicSubnets are passed as input parameters.
# Set use_existing_vcn = false (default) to provision all networking.
variable "use_existing_vcn" {
  description = "When true, reference existing VCN/subnets via OCIDs (mirrors CFN VpcId/SubnetIds parameters). When false, create all networking from scratch."
  type        = bool
  default     = false
}

variable "existing_vcn_id" {
  description = "OCID of an existing VCN. Required when use_existing_vcn = true."
  type        = string
  default     = ""
}

variable "existing_public_subnet_ids" {
  description = "List of exactly two existing public subnet OCIDs (used for the load balancer). Required when use_existing_vcn = true. Maps CFN Parameter: PublicSubnets."
  type        = list(string)
  default     = []
}

variable "existing_private_app_subnet_ids" {
  description = "List of exactly two existing private app subnet OCIDs. Required when use_existing_vcn = true. Maps CFN Parameter: PrivateSubnets (app tier)."
  type        = list(string)
  default     = []
}

variable "existing_private_db_subnet_id" {
  description = "OCID of an existing private database subnet. Required when use_existing_vcn = true. Maps CFN Parameter: PrivateSubnets (db tier)."
  type        = string
  default     = ""
}

variable "vcn_cidr" {
  description = "CIDR block for the new VCN. Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.0.0/16"
}

variable "public_subnet_cidr_1" {
  description = "CIDR block for public subnet 1 (AD-1, load balancer). Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.0.0/24"
}

variable "public_subnet_cidr_2" {
  description = "CIDR block for public subnet 2 (AD-2, load balancer). Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.1.0/24"
}

variable "private_app_subnet_cidr_1" {
  description = "CIDR block for private app subnet 1 (AD-1). Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.10.0/24"
}

variable "private_app_subnet_cidr_2" {
  description = "CIDR block for private app subnet 2 (AD-2). Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.11.0/24"
}

variable "private_db_subnet_cidr" {
  description = "CIDR block for private database subnet. Used when use_existing_vcn = false."
  type        = string
  default     = "10.0.20.0/24"
}

# --- Database ---
variable "db_password" {
  description = "Admin password for the PostgreSQL DB System. Maps CFN Parameter: DBPassword (NoEcho: true). Minimum 12 characters; must include upper, lower, digit, and special character."
  type        = string
  sensitive   = true

  validation {
    condition     = length(var.db_password) >= 12
    error_message = "Database password must be at least 12 characters."
  }
}

variable "db_storage_size_gb" {
  description = "Storage size in GB for the PostgreSQL DB System. Maps CFN RDS AllocatedStorage: 50. Minimum 50 GB."
  type        = number
  default     = 50

  validation {
    condition     = var.db_storage_size_gb >= 50
    error_message = "db_storage_size_gb must be at least 50 GB."
  }
}

variable "db_backup_retention_days" {
  description = "Number of days to retain automatic database backups. Maps CFN RDS BackupRetentionPeriod: 7."
  type        = number
  default     = 7

  validation {
    condition     = var.db_backup_retention_days >= 1 && var.db_backup_retention_days <= 35
    error_message = "db_backup_retention_days must be between 1 and 35."
  }
}

# --- OKE Cluster ---
variable "kubernetes_version" {
  description = "Kubernetes version for the OKE cluster (e.g., v1.30.1). Check OCI Console for available versions in your region."
  type        = string
  default     = "v1.30.1"
}

variable "app_desired_count" {
  description = "Desired (minimum) number of application pod replicas. Maps CFN AppService.DesiredCount: 2."
  type        = number
  default     = 2

  validation {
    condition     = var.app_desired_count >= 1
    error_message = "app_desired_count must be at least 1."
  }
}

variable "app_max_count" {
  description = "Maximum number of application pod replicas for the Horizontal Pod Autoscaler."
  type        = number
  default     = 10

  validation {
    condition     = var.app_max_count >= var.app_desired_count
    error_message = "app_max_count must be >= app_desired_count."
  }
}

# --- Kubernetes Workload ---
variable "k8s_namespace" {
  description = "Kubernetes namespace in which to deploy the application workload."
  type        = string
  default     = "acme-app"
}

variable "ocir_pull_secret_name" {
  description = "Name of the Kubernetes docker-registry secret for OCIR image pulls. Pre-create with: kubectl create secret docker-registry <name> --docker-server=<region>.ocir.io --docker-username='<namespace>/<user>' --docker-password='<auth-token>' -n <k8s_namespace>"
  type        = string
  default     = "ocir-pull-secret"
}

variable "app_image_uri" {
  description = "Full OCIR image URI for the application container (e.g., us-ashburn-1.ocir.io/myns/acme-app:latest). Leave empty to auto-construct from region and namespace."
  type        = string
  default     = ""
}

# --- Load Balancer / TLS ---
variable "ssl_certificate_name" {
  description = "Name of an SSL certificate already loaded into the OCI Load Balancer Certificates service. Leave empty to skip the HTTPS listener (port 443)."
  type        = string
  default     = ""
}

# --- Monitoring & Alerting ---
variable "alert_email" {
  description = "Email address for monitoring alarm notifications via OCI ONS. Leave empty to skip the email subscription."
  type        = string
  default     = ""
}

outputs_tf:
# =============================================================================
# Outputs – OCI 3-Tier Web Application
# =============================================================================

# --- Load Balancer ---
output "lb_public_ip" {
  description = "Public IP address of the OCI Load Balancer. Maps CFN Output: ALBEndpoint (DNS-based)."
  value       = oci_load_balancer_load_balancer.alb.ip_addresses[0].ip_address
}

output "lb_http_endpoint" {
  description = "HTTP endpoint URL of the OCI Load Balancer. Maps CFN Output: ALBEndpoint."
  value       = "http://${oci_load_balancer_load_balancer.alb.ip_addresses[0].ip_address}"
}

output "lb_https_endpoint" {
  description = "HTTPS endpoint URL (available only when ssl_certificate_name is set)."
  value       = var.ssl_certificate_name != "" ? "https://${oci_load_balancer_load_balancer.alb.ip_addresses[0].ip_address}" : "HTTPS listener not configured – set ssl_certificate_name to enable."
}

output "lb_ocid" {
  description = "OCID of the OCI Load Balancer."
  value       = oci_load_balancer_load_balancer.alb.id
}

# --- Database ---
output "db_primary_endpoint" {
  description = "Private FQDN of the PostgreSQL DB System primary endpoint. Maps CFN Output: DatabaseEndpoint. Use this as DB_HOST in application configuration."
  value       = length(oci_psql_db_system.app_db.endpoints) > 0 ? oci_psql_db_system.app_db.endpoints[0].fqdn : "pending"
}

output "db_connection_string" {
  description = "PostgreSQL JDBC connection string. Standard wire protocol – no wallet required."
  value       = length(oci_psql_db_system.app_db.endpoints) > 0 ? "jdbc:postgresql://${oci_psql_db_system.app_db.endpoints[0].fqdn}:5432/appdb" : "pending"
  sensitive   = false
}

output "db_ocid" {
  description = "OCID of the OCI PostgreSQL DB System."
  value       = oci_psql_db_system.app_db.id
}

# --- OKE Cluster ---
output "oke_cluster_id" {
  description = "OCID of the OKE cluster. Maps CFN Output: ClusterName."
  value       = oci_containerengine_cluster.app_cluster.id
}

output "oke_cluster_name" {
  description = "Display name of the OKE cluster."
  value       = oci_containerengine_cluster.app_cluster.name
}

output "oke_kubeconfig_command" {
  description = "OCI CLI command to generate a kubeconfig for the OKE cluster. Run after Phase-1 apply completes."
  value       = "oci ce cluster create-kubeconfig --cluster-id ${oci_containerengine_cluster.app_cluster.id} --region ${var.region} --token-version 2.0.0 --kube-endpoint PRIVATE_ENDPOINT --file ~/.kube/config"
}

# --- Kubernetes Workload ---
output "k8s_namespace" {
  description = "Kubernetes namespace where the application workload is deployed."
  value       = kubernetes_namespace.app.metadata[0].name
}

output "k8s_deployment_name" {
  description = "Kubernetes Deployment name (equivalent to ECS Service name 'app-service')."
  value       = kubernetes_deployment.app.metadata[0].name
}

output "k8s_service_name" {
  description = "Kubernetes Service name that routes traffic through the OCI Load Balancer."
  value       = kubernetes_service.app.metadata[0].name
}

output "k8s_hpa_name" {
  description = "Name of the Horizontal Pod Autoscaler (maps HighCPUAlarm-driven ECS scaling)."
  value       = kubernetes_horizontal_pod_autoscaler_v2.app.metadata[0].name
}

# --- Container Registry ---
output "ocir_repository_url" {
  description = "Full OCIR repository push/pull URL for the application image."
  value       = "${var.region}.ocir.io/${data.oci_objectstorage_namespace.ns.namespace}/${oci_artifacts_container_repository.app.display_name}"
}

# --- Secrets & Vault ---
output "db_vault_secret_id" {
  description = "OCID of the OCI Vault Secret storing the database password."
  value       = oci_vault_secret.db_password.id
  sensitive   = true
}

output "vault_id" {
  description = "OCID of the OCI KMS Vault."
  value       = oci_kms_vault.app.id
}

# --- Networking ---
output "vcn_id" {
  description = "OCID of the VCN (new or existing). Maps CFN Parameter: VpcId."
  value       = local.vcn_id
}

output "public_subnet_ids" {
  description = "OCIDs of the two public subnets used by the load balancer. Maps CFN Parameter: PublicSubnets."
  value       = [local.public_subnet_1_id, local.public_subnet_2_id]
}

output "private_app_subnet_ids" {
  description = "OCIDs of the two private application subnets used by OKE. Maps CFN Parameter: PrivateSubnets."
  value       = [local.private_app_1_id, local.private_app_2_id]
}

output "private_db_subnet_id" {
  description = "OCID of the private database subnet."
  value       = local.private_db_id
}

# --- Monitoring ---
output "ons_alert_topic_id" {
  description = "OCID of the ONS notification topic used by monitoring alarms."
  value       = oci_ons_notification_topic.alerts.id
}
